sp_widget.client_script:
api.controller = function($location){

  var c = this;
  c.browsingTables = false;
  c.cid = sessionStorage.getItem('currentId');

  c.isActive = function(page){
    return $location.search().id === page;
  };

  c.getCartCount = function(){
    var cart = JSON.parse(sessionStorage.getItem("migration_cart") || "[]");
    return cart.length;
  };

	/* =========================
       BROWSE TABLES LOADER
    ========================== */
c.startBrowse = function() {
    c.browsingTables = true;
};

};

sp_widget.css:
*{
  outline-style:none!important;
}
.dm-sidebar{
  width:100%;
  height:calc(100vh - 64px);
  background:#fff;
  border-right:1px solid #edf0f5;
  padding:22px 14px;
}
.dm-menu{
  list-style:none;
  padding:0;
  margin:0;
  display:flex;
  flex-direction:column;
  gap:8px;
}
.dm-menu a{
  display:flex;
  align-items:center;
  padding:10px 12px;
  border-radius:16px;
  text-decoration:none;
  font-size:15px;
  font-weight:500;
  color:#3b4455;
  transition:all .25s ease;
}
.dm-menu a:focus,
.dm-menu a:active,
.dm-menu a:focus-visible {
  outline: none !important;
  box-shadow: none !important;
}
.dm-icon-box{
  width:36px;
  height:36px;
  border-radius:11px;
  background:#f5f7fb;
  display:flex;
  align-items:center;
  justify-content:center;
  margin-right:13px;
  flex-shrink:0;
}
.dm-icon-box svg{
  width:17px;
  height:17px;
  stroke:#116AF8;
  stroke-width:1.7;
  stroke-linecap:round;
  stroke-linejoin:round;
}
.dm-text{
  flex:1;
  line-height:1.25;
}
.dm-right{
  display:flex;
  align-items:center;
  gap:10px;
}
.dm-arrow{
  width:16px;
  height:16px;
  stroke:#116AF8;
  stroke-width:2;
  opacity:0;
  visibility:hidden;
  flex-shrink:0;
  transition:all .2s ease;
}
.cart-badge{
  background:#116AF8;
  color:#fff;
  font-size:11px;
  min-width:20px;
  height:20px;
  border-radius:4px;
  display:flex;
  align-items:center;
  justify-content:center;
  padding:0 6px;
}
.cart-li.active .cart-badge{
  background:#9BC0FC;
  color:#000;
}
.cart-li:hover .cart-badge{
  background:#9BC0FC;
  color:#000;
}
.dm-menu li:not(.active) a:hover{
  background:#116AF8;
  color:#fff;
}
.dm-menu li.active a{
  background: linear-gradient(to right, #116AF8, #0A50F5);
  transition: all 2s ease-out;
  color:#fff;
  box-shadow:0 8px 22px rgba(17,106,248,.22);
}
.dm-menu li.active .dm-icon-box{
  background:rgba(255,255,255,.15);
}
.dm-menu li.active .dm-icon-box svg{
  stroke:#fff;
}
.dm-menu li.active .dm-arrow{
  opacity:1;
  visibility:visible;
  stroke:#fff;
}

/* ================================
   FULL-PAGE LOADER OVERLAY
================================ */
.dm-page-loader-overlay {
    position: fixed;
    inset: 0;

    /* Blurry transparent gradient using your colors */
    background: linear-gradient(
        135deg,
        rgba(17, 106, 248, 0.08),
        rgba(10, 80, 245, 0.10),
        rgba(155, 192, 252, 0.08)
    );

    backdrop-filter: blur(14px);
    -webkit-backdrop-filter: blur(14px);

    z-index: 9999;
    display: flex;
    align-items: center;
    justify-content: center;

    animation: dm-fade-in 0.3s ease;
}

@keyframes dm-fade-in {
    from { opacity: 0; }
    to   { opacity: 1; }
}

/* Subtle glow background */
.dm-page-loader-overlay::before {
    content: "";
    position: absolute;
    width: 400px;
    height: 400px;
    background: radial-gradient(
        circle,
        rgba(17, 106, 248, 0.25),
        transparent 70%
    );
    filter: blur(60px);
    z-index: -1;
}

/* ================================
   LOADER CARD
================================ */
.dm-page-loader-box {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 16px;

    /* Glass effect card */
    background: rgba(255, 255, 255, 0.65);
    backdrop-filter: blur(18px);
    -webkit-backdrop-filter: blur(18px);

    padding: 50px 60px;
    border-radius: 22px;

    border: 1px solid rgba(155, 192, 252, 0.35);

    box-shadow:
        0 12px 50px rgba(17, 106, 248, 0.25),
        0 0 0 1px rgba(17, 106, 248, 0.08),
        inset 0 1px 0 rgba(255,255,255,0.6);

    min-width: 340px;

    animation: dm-slide-up 0.35s ease;
}

@keyframes dm-slide-up {
    from { transform: translateY(20px); opacity: 0; }
    to   { transform: translateY(0);    opacity: 1; }
}

/* ================================
   LOGO
================================ */
.dm-loader-logo {
    width: 78px;
    height: 78px;
    border-radius: 0 !important;
    background: transparent !important;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow:none !important;
    margin-bottom: 6px;
    animation: dm-pulse-logo 1.8s ease-in-out infinite;
}

@keyframes dm-pulse-logo {
    0%, 100% { box-shadow: 0 8px 30px rgba(17, 106, 248, 0.45); }
    50%       { box-shadow: 0 8px 45px rgba(17, 106, 248, 0.7);  }
}

/* ================================
   TEXT
================================ */
.dm-loader-title {
    font-size: 18px;
    font-weight: 700;
    color: #0A50F5;
    letter-spacing: -0.3px;
    margin-top: 4px;
}

.dm-loader-subtitle {
    font-size: 13px;
    color: #6b7280;
    text-align: center;
    max-width: 240px;
    line-height: 1.5;
}

/* ================================
   PROGRESS BAR
================================ */
.dm-progress-track {
    width: 100%;
    height: 6px;
    background: #e8f0fe;
    border-radius: 99px;
    overflow: hidden;
    margin-top: 6px;
}

.dm-progress-bar {
    height: 100%;
    width: 40%;
    border-radius: 99px;

    background: linear-gradient(
        90deg,
        #116AF8,
        #9BC0FC,
        #0A50F5,
        #116AF8
    );

    background-size: 300% 100%;

    animation: dm-progress-slide 1.3s ease-in-out infinite;
}

@keyframes dm-progress-slide {
    0%   { background-position: 100% 0; width: 30%; margin-left: 0%;   }
    50%  { background-position: 0% 0;   width: 55%; margin-left: 20%;  }
    100% { background-position: 100% 0; width: 30%; margin-left: 70%;  }
}

/* ================================
   DOTS
================================ */
.dm-loader-dots {
    display: flex;
    gap: 7px;
    margin-top: 4px;
}

.dm-loader-dots span {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: #9BC0FC;
    animation: dm-dot-bounce 1.2s ease-in-out infinite;
}

.dm-loader-dots span:nth-child(1) { animation-delay: 0s;    background: #116AF8; }
.dm-loader-dots span:nth-child(2) { animation-delay: 0.2s;  background: #0A50F5; }
.dm-loader-dots span:nth-child(3) { animation-delay: 0.4s;  background: #9BC0FC; }

@keyframes dm-dot-bounce {
    0%, 80%, 100% { transform: scale(0.8); opacity: 0.5; }
    40%            { transform: scale(1.3); opacity: 1;   }
}
